   293→        let idx5 = bytecode.add_constant(5);
   294→        let idx3 = bytecode.add_constant(3);
   295→
   296→        // PUSH 5
   297→        bytecode.add_instruction(OpCode::OpConstant.as_byte());
   298→        bytecode.add_instruction((idx5 >> 8) as u8);
   299→        bytecode.add_instruction((idx5 & 0xFF) as u8);
   300→
   301→        // PUSH 3
   302→        bytecode.add_instruction(OpCode::OpConstant.as_byte());
   303→        bytecode.add_instruction((idx3 >> 8) as u8);
   304→        bytecode.add_instruction((idx3 & 0xFF) as u8);
   305→
   306→        // ADD
   307→        bytecode.add_instruction(OpCode::OpAdd.as_byte());
   308→
   309→        let mut vm = VM::new(bytecode);
