   312→        assert_eq!(result, Value::Int(8));
   313→    }
   314→
   315→    #[test]
   316→    fn test_boolean() {
   317→        let mut bytecode = Bytecode::new();
   318→        bytecode.add_instruction(OpCode::OpTrue.as_byte());
   319→
   320→        let mut vm = VM::new(bytecode);
   321→        let result = vm.run().unwrap();
   322→
   323→        assert_eq!(result, Value::Bool(true));
   324→    }
   325→
   326→    #[test]
   327→    fn test_array() {
   328→        let mut bytecode = Bytecode::new();
   329→        let idx1 = bytecode.add_constant(1);
   330→        let idx2 = bytecode.add_constant(2);
   331→        let idx3 = bytecode.add_constant(3);
   332→
   333→        // PUSH 1
   334→        bytecode.add_instruction(OpCode::OpConstant.as_byte());
   335→        bytecode.add_instruction((idx1 >> 8) as u8);
   336→        bytecode.add_instruction((idx1 & 0xFF) as u8);
   337→
   338→        // PUSH 2
   339→        bytecode.add_instruction(OpCode::OpConstant.as_byte());
   340→        bytecode.add_instruction((idx2 >> 8) as u8);
   341→        bytecode.add_instruction((idx2 & 0xFF) as u8);
   342→
   343→        // PUSH 3
   344→        bytecode.add_instruction(OpCode::OpConstant.as_byte());
   345→        bytecode.add_instruction((idx3 >> 8) as u8);
   346→        bytecode.add_instruction((idx3 & 0xFF) as u8);
   347→
   348→        // ARRAY 3
   349→        bytecode.add_instruction(OpCode::OpArray.as_byte());
   350→        bytecode.add_instruction(0);
   351→        bytecode.add_instruction(3);
   352→
   353→        let mut vm = VM::new(bytecode);
   354→        let result = vm.run().unwrap();
   355→
   356→        assert_eq!(
